	.TITLE	LUTIN	.PROC	M680002		; mnmonics CALM 2	.RADIX	10.		; base 10 par dfaut	.HEX			; listing en hexadcima	.REF	SM8		; df diverses	.REF	NTREL		; df noyau temps rel	.REF	GESMEM		; df gestionnaire de mmoire	.REF	FOS		; df file operating system	.REF	LIB		; df librairie	.REF	DRIVERS		; df drivers	.REF	GRA		; df module graphique; Variables; ---------	.LOC	0OFLAGS:	.BLKB	2		; flags diversOBUSTD:	.BLKB	LGDIS4OBUWRI:	.BLKB	30LGVAR:; Programme; ---------	.LOC	0START:	.W	LIB,?OPELIB	; ouvre la librairie	LOAD.B	D3,#2	.W	LIB,?MOUSE	LOAD.L	D4,#LGVAR	.W	GESMEM,?GETMEM	; demande mmoire pour var.	JUMP,NE	ER	LOAD.L	A6,A4		; A6 <-- ^variables	CLR.B	(A6)+OFLAGS	; clear tous les flags	JUMP	ESSAIER:	PUSH.W	D7		; sauve l'erreur	.W	LIB,?AFCR	; passe  la ligne	POP.W	D7		; reprend l'erreur	.W	LIB,?AFERROR	; affiche l'erreur	.W	LIB,?GETCAR	; attend une toucheRETOUR:	LOAD.B	D3,#EOP	.W	LIB,?AFCAR	; efface toute la fentre	.W	LIB,?CLOLIB	; ferme la librairie	.W	FOS,?STOP	; avorte le processus ...ESSAI:	.W	LIB,?AFTIM	.B	AFCCMO	.B	NOCURS	.B	0	.EVEN	LOAD.W	D3,#0	SWAP.W	D3	LOAD.W	D3,#50	LOAD.W	D4,#350	SWAP.W	D4	LOAD.W	D4,#0	LOAD.W	D2,#SETDOT	.W	LIB,?DRSEG	LOAD.L	D3,#-1	LOAD.L	D4,#-1	.W	LIB,?DRMDEF	LOAD.W	D3,#100	SWAP.W	D3	LOAD.W	D3,#100	LOAD.W	D4,#80	SWAP.W	D4	LOAD.W	D4,#80	LOAD.W	D2,#SETDOT	.W	LIB,?DRMATRIX	LOAD.L	D3,#H'AA55AA55	LOAD.L	D4,#H'AA55AA55	.W	LIB,?DRMDEF	LOAD.W	D3,#100	SWAP.W	D3	LOAD.W	D3,#200	LOAD.W	D4,#80	SWAP.W	D4	LOAD.W	D4,#80	LOAD.W	D2,#SETDOT	.W	LIB,?DRMATRIX	LOAD.L	D3,#H'AAAAAAAA	LOAD.L	D4,#H'AAAAAAAA	.W	LIB,?DRMDEF	LOAD.W	D3,#200	SWAP.W	D3	LOAD.W	D3,#100	LOAD.W	D4,#80	SWAP.W	D4	LOAD.W	D4,#80	LOAD.W	D2,#SETDOT	.W	LIB,?DRMATRIX	LOAD.L	D3,#H'88002200	LOAD.L	D4,#H'88002200	.W	LIB,?DRMDEF	LOAD.W	D3,#200	SWAP.W	D3	LOAD.W	D3,#200	LOAD.W	D4,#80	SWAP.W	D4	LOAD.W	D4,#80	LOAD.W	D2,#SETDOT	.W	LIB,?DRMATRIX	LOAD.L	A4,#(A6)+OBUSTD	LOAD.L	D4,#LGDIS4	LOAD.W	D3,#TYPWDO	.W	LIB,?GCHDIS	.W	FOS,?RSTATUS	JUMP,NE	ER	LOAD.L	A2,A4		; A2 <-- ^description de la fentre	LOAD.W	D4,#50	SWAP.W	D4	CLR.W	D4	LOAD.L	A4,#R16"MOTS1	LOAD.L	A3,#R16"MOTC1	ADD.W	D4,#50	CLR.L	D3	LOAD.B	D3,(A4)+1	SWAP.W	D3	LOAD.B	D3,(A4)+0	ADD.L	A4,#2	ADD.L	A3,#2	LOAD.W	D6,#0	CALL	OPEN_SPRITE	; dessine le premier	LOAD.L	A4,#R16"MOTS2	LOAD.L	A3,#R16"MOTC2	ADD.W	D4,#50	CLR.L	D3	LOAD.B	D3,(A4)+1	SWAP.W	D3	LOAD.B	D3,(A4)+0	ADD.L	A4,#2	ADD.L	A3,#2	LOAD.W	D6,#1	CALL	OPEN_SPRITE	; dessine le premier	LOAD.L	A4,#R16"MOTS5	LOAD.L	A3,#R16"MOTC5	ADD.W	D4,#50	CLR.L	D3	LOAD.B	D3,(A4)+1	SWAP.W	D3	LOAD.B	D3,(A4)+0	ADD.L	A4,#2	ADD.L	A3,#2	LOAD.W	D6,#2	CALL	OPEN_SPRITE	; dessine le premier	LOAD.L	A4,#R16"MOTS4	LOAD.L	A3,#R16"MOTC4	ADD.W	D4,#50	CLR.L	D3	LOAD.B	D3,(A4)+1	SWAP.W	D3	LOAD.B	D3,(A4)+0	ADD.L	A4,#2	ADD.L	A3,#2	LOAD.W	D6,#3	CALL	OPEN_SPRITE	; dessine le premier	LOAD.L	A4,#R16"MOTS3	LOAD.L	A3,#R16"MOTC3	ADD.W	D4,#50	CLR.L	D3	LOAD.B	D3,(A4)+1	SWAP.W	D3	LOAD.B	D3,(A4)+0	ADD.L	A4,#2	ADD.L	A3,#2	LOAD.W	D6,#4	CALL	OPEN_SPRITE	; dessine le premier	LOAD.L	A4,#R16"MOTS3	LOAD.L	A3,#R16"MOTC31	ADD.W	D4,#50	CLR.L	D3	LOAD.B	D3,(A4)+1	SWAP.W	D3	LOAD.B	D3,(A4)+0	ADD.L	A4,#2	ADD.L	A3,#2	LOAD.W	D6,#5	CALL	OPEN_SPRITE	; dessine le premier20$:	.W	LIB,?GETKEY	TEST.L	D3:#BKPSEUDO	JUMP,BS	20$	COMP.W	D3,#END	JUMP,EQ	RETOUR	COMP.W	D3,#KEYMMP	JUMP,EQ	60$	COMP.W	D3,#KEYMPO	JUMP,EQ	40$	COMP.W	D3,#'0	JUMP,LO	20$	COMP.W	D3,#'5	JUMP,HI	20$	SUB.W	D3,#'0	LOAD.W	D6,D3	JUMP	20$40$:	.W	LIB,?IFMOUSE	JUMP,NE	20$	CALL	MOVE_SPRITE	; dplace	JUMP	20$60$:	CALL	CLEAR_SPRITE	; efface65$:	.W	LIB,?GETKEY	TEST.L	D3:#BKPSEUDO	JUMP,BS	65$	COMP.W	D3,#KEYMMR	JUMP,NE	65$	CALL	MOVE_SPRITE	; remet	JUMP	20$OPEN_SPRITE:	PUSHM.L	D3,D4,A0,A3	LOAD.L	A0,A3	LOAD.L	A3,#(A6)+OBUWRI+1	LOAD.B	(A3)+0,#DRAWOSPRITE	SWAP.W	D4	LOAD.L	(A3)+1,D4	; <xx> <yy>	SWAP.W	D3	LOAD.L	(A3)+5,D3	; <dx> <dy>	LOAD.L	(A3)+9,A4	; <ssss>	LOAD.L	(A3)+13,A0	; <cccc>	LOAD.B	(A3)+17,D6	; <n>	LOAD.W	D3,#18	.W	LIB,?STRING	POPM.L	D3,D4,A0,A3	RETMOVE_SPRITE:	PUSHM.L	D3,D4,A3	LOAD.L	A3,#(A6)+OBUWRI+1	LOAD.B	(A3)+0,#DRAWMSPRITE	SWAP.W	D4	LOAD.L	(A3)+1,D4	; <xx> <yy>	LOAD.B	(A3)+5,D6	; <n>	LOAD.W	D3,#6	.W	LIB,?STRING	POPM.L	D3,D4,A3	RETCLEAR_SPRITE:	PUSHM.L	D3,D4,A3	LOAD.L	A3,#(A6)+OBUWRI+1	LOAD.B	(A3)+0,#DRAWESPRITE	LOAD.B	(A3)+1,D6	; <n>	LOAD.W	D3,#2	.W	LIB,?STRING	POPM.L	D3,D4,A3	RETMOTIF:	.B	B'11100000,B'00000011,B'11111111,B'00000000	.B	B'11100000,B'00000010,B'11111111,B'00000000	.B	B'11100000,B'00000110,B'01111111,B'00000000	.B	B'00010000,B'00001000,B'01111111,B'00000000	.B	B'00001000,B'00010000,B'00111111,B'00000000	.B	B'00000100,B'00100000,B'00111111,B'00000000	.B	B'00000010,B'01000000,B'00011111,B'00000000	.B	B'00000001,B'10000000,B'00011111,B'00000000	.B	B'00000001,B'10000000,B'00001111,B'00000000	.B	B'00000010,B'01000000,B'00001111,B'00000000	.B	B'00000100,B'00100000,B'00000111,B'00000000	.B	B'00001000,B'00010000,B'00000111,B'00000000	.B	B'00010000,B'00001000,B'00000011,B'00000000	.B	B'00100000,B'00000110,B'00000011,B'00000000	.B	B'01000000,B'00000010,B'00000001,B'00000000	.B	B'10000000,B'00000011,B'00000001,B'00000000	.EVENMOTS1:	.B	19,19	.B	B'00000000,B'00000000,B'00000000	.B	B'00000000,B'00000000,B'00000000	.B	B'00111111,B'11111100,B'00000000	.B	B'00111111,B'11111000,B'00000000	.B	B'00111111,B'11110000,B'00000000	.B	B'00111111,B'11100000,B'00000000	.B	B'00111111,B'11100000,B'00000000	.B	B'00111111,B'11110000,B'00000000	.B	B'00111111,B'11111000,B'00000000	.B	B'00111111,B'11111100,B'00000000	.B	B'00111111,B'11111110,B'00000000	.B	B'00111001,B'11111111,B'00000000	.B	B'00110000,B'11111111,B'10000000	.B	B'00100000,B'01111111,B'00000000	.B	B'00000000,B'00111110,B'00000000	.B	B'00000000,B'00011100,B'00000000	.B	B'00000000,B'00001000,B'00000000	.B	B'00000000,B'00000000,B'00000000	.B	B'00000000,B'00000